#include <stdio.h>
#include <math.h>
#define MOD 998244353

long long fibo[200004];

long long power(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

int main() {
    fibo[0] = 1;
    fibo[1] = 1;
    for (int i = 2; i < 200002; i++) {
        fibo[i] = (fibo[i-1] + fibo[i-2]) % MOD;
    }

    int n;
    scanf("%d", &n);
    long long deno = 1LL << n;
    long long inv = power(deno, MOD-2, MOD);
    long long ans = (fibo[n-1] * inv) % MOD;
    printf("%lld\n", ans);
    return 0;
}
